"python3 -c \"\nimport os\nfor root, dirs, files in os.walk('.'):\n    if '.venv' in root or '.git' in root or 'venv' in root:\n        continue\n    for file in files:\n        if file.endswith('.py'):\n            path = os.path.join(root, file)\n            try:\n                with open(path, 'r', errors='ignore') as f:\n                    content = f.read()\n                    if 'def _modal_daily_menu' in content or 'def _master_daily_menu' in content or '_build_slots' in content:\n                        print(f'Found in {path}')\n            except:\n                pass\n\""